do $IMPERIUM$
declare
  v_game uuid;
  v_section uuid;
begin
  select id into v_game from public.games where slug = 'sword-x-staff';
  if v_game is null then
    raise exception 'IMPERIUM: juego no encontrado: %', 'sword-x-staff';
  end if;

  delete from public.section_blocks where section_id in (
    select id from public.game_sections where game_id = v_game and slug = 'builds');
  delete from public.game_sections where game_id = v_game and slug = 'builds';

  insert into public.game_sections
    (game_id, slug, title, intro_title, intro, intro_images, is_published,
     label, description, icon, cover_image, render_type, order_index)
  values
    (v_game, 'builds', 'Builds — Sword x Staff', 'Builds por Clase y Tier',
     'Cargas para las 6 clases jugables organizadas por tier de trabajo (T1→T2). Los builds de Mago están curados por EOG; los demás están construidos con el pool de habilidades y descripciones oficiales de eog.gg. El meta evoluciona: ajusta según el parche.',
     array['https://eog.gg/assets/sxs/classes/warrior.png']::text[], false,
     'Builds', 'Loadouts por tier y clase: Guerrero, Duelista, Caballero, Mago, Hechicero, Sabio', 'wrench',
     'https://eog.gg/assets/sxs/classes/warrior.png', 'builds', 4)
  returning id into v_section;

  insert into public.section_blocks
    (section_id, order_index, title, content, source_url, is_verified, images, meta)
  values
    (v_section, 1, 'T1 — 1er Trabajo', '__BUILDS__{"tier":"T1","label":"1er Trabajo","classes":[{"class":"Warrior","class_es":"Guerrero","icon":"https://eog.gg/assets/sxs/classes/warrior.png","builds":[{"name":"Principiante","mode":"PvE","techniques":[{"name":"Whirlwind Slash","img":"https://eog.gg/assets/sxs/skills/whirlwind-slash.webp"},{"name":"Leap Attack","img":"https://eog.gg/assets/sxs/skills/leap-attack.webp"},{"name":"Heavy Impact","img":"https://eog.gg/assets/sxs/skills/heavy-impact.webp"},{"name":"Edge Strike","img":"https://eog.gg/assets/sxs/skills/edge-strike.webp"}],"enchants":[{"name":"Warrior''s Essence","img":"https://eog.gg/assets/sxs/skills/warriors-essence.webp"},{"name":"Iron Fortress","img":"https://eog.gg/assets/sxs/skills/iron-fortress.webp"},{"name":"Crystal Armor","img":"https://eog.gg/assets/sxs/skills/crystal-armor.webp"},{"name":"Life Blessing","img":"https://eog.gg/assets/sxs/skills/life-blessing.webp"}],"desc":"Carga de inicio para el Guerrero base. Whirlwind Slash y Leap Attack cubren AoE; Crystal Armor e Iron Fortress sostienen la defensa antes del 2nd Job Change."},{"name":"DPS Sostenido","mode":"PvE","techniques":[{"name":"Whirlwind Slash","img":"https://eog.gg/assets/sxs/skills/whirlwind-slash.webp"},{"name":"Lion Combo","img":"https://eog.gg/assets/sxs/skills/lion-combo.webp"},{"name":"Mountain Collapse","img":"https://eog.gg/assets/sxs/skills/mountain-collapse.webp"},{"name":"Quadrant Slash","img":"https://eog.gg/assets/sxs/skills/quadrant-slash.webp"}],"enchants":[{"name":"Blade Tempest","img":"https://eog.gg/assets/sxs/skills/blade-tempest.webp"},{"name":"Relentless Frenzy","img":"https://eog.gg/assets/sxs/skills/relentless-frenzy.webp"},{"name":"Warrior''s Essence","img":"https://eog.gg/assets/sxs/skills/warriors-essence.webp"},{"name":"Feline Dance","img":"https://eog.gg/assets/sxs/skills/feline-dance.webp"}],"desc":"Carga orientada al DPS. Lion Combo y Mountain Collapse maximizan el burst; Blade Tempest y Relentless Frenzy 